import{_ as s,c as a,o as i,b as d}from"./app.56f378f3.js";const h='{"title":"\u0413\u043B\u0430\u0432\u0430 14","description":"","frontmatter":{"title":"\u0413\u043B\u0430\u0432\u0430 14","subtitle":"\u041C\u0430\u043B\u0438\u043D\u0438 \u0432\u0438\u0434\u0436\u0430\u0439\u043E\u0442\u0442\u0430\u0440\u0430 \u0442\u0430\u043D\u0442\u0440\u0430","tags":"malini","date":"2020-08-01T00:00:00.000Z"},"headers":[],"relativePath":"texts/malini-vijayottara/14/index.md"}',n={},c=d('<div class="stanza"><a href="#s14.1" id="s14.1" class="num">14.1</a><p>\u0422\u0435\u043F\u0435\u0440\u044C \u043F\u043E\u0432\u0435\u0434\u0430\u044E \u043E \u0434\u0445\u0430\u0440\u0430\u043D\u0430\u0445 \u043D\u0430 \u0442\u0430\u043D\u043C\u0430\u0442\u0440\u0430\u0445, \u043F\u043E \u043F\u043E\u0440\u044F\u0434\u043A\u0443, \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u0437\u0430\u043F\u0430\u0445\u0430, \u0438 \u043E \u043F\u043B\u043E\u0434\u0430\u0445 \u0438\u0445 \u0440\u0435\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u0438 .</p></div><div class="stanza"><a href="#s14.2" id="s14.2" class="num">14.2</a><p>\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0443\u044E \u0432 \u043D\u0430 \u0432\u0435\u0440\u0448\u0438\u043D\u0435 \u043D\u043E\u0437\u0434\u0440\u0435\u0432\u044B\u0445 \u043E\u0442\u0432\u0435\u0440\u0441\u0442\u0438\u0439 \u0433\u0430\u043D\u0434\u0445\u0430 \u0442\u0430\u043D\u043C\u0430\u0442\u0440\u0443, \u0436\u0435\u043B\u0442\u0443\u044E, \u0447\u0435\u0442\u044B\u0440\u0435\u0445\u0443\u0433\u043E\u043B\u044C\u043D\u0443\u044E, \u043F\u043E\u0434\u043E\u0431\u043D\u0443\u044E \u0433\u043E\u0440\u0435, \u043E\u0442\u043C\u0435\u0447\u0435\u043D\u043D\u0443\u044E \u0437\u043D\u0430\u043A\u0430\u043C\u0438 \u0432\u0430\u0434\u0436\u0440\u044B .</p></div><div class="stanza"><a href="#s14.3" id="s14.3" class="num">14.3</a><p>\u0419\u043E\u0433\u0438\u043D, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0435\u0442 \u0435\u0435 \u0431\u043E\u043B\u0435\u0435 \u0434\u0435\u0441\u044F\u0442\u0438 \u0434\u043D\u0435\u0439 \u043D\u0435 \u043E\u0442\u0432\u043B\u0435\u043A\u0430\u044F\u0441\u044C \u0443\u043C\u043E\u043C, \u043A\u0430\u043A\u043E\u0439 \u0437\u0430\u043F\u0430\u0445 \u043D\u0435 \u0441\u043C\u043E\u0436\u0435\u0442 \u043E\u0431\u0440\u0435\u0441\u0442\u0438, \u0434\u0432\u043E\u044F\u043A\u0438\u0439 \u0438 \u043C\u043D\u043E\u0433\u043E\u043E\u0431\u0440\u0430\u0437\u043D\u044B\u0439?</p></div><div class="stanza"><a href="#s14.4" id="s14.4" class="num">14.4</a><p>\u0417\u0430\u0442\u0435\u043C \u0437\u0430 \u043E\u0434\u0438\u043D \u0441\u0435\u0437\u043E\u043D \u0434\u043B\u044F \u043D\u0435\u0433\u043E \u0431\u043B\u0430\u0433\u043E\u0439 \u0437\u0430\u043F\u0430\u0445 \u0441\u0442\u0430\u043D\u0435\u0442 \u0443\u0441\u0442\u043E\u0439\u0447\u0438\u0432\u044B\u043C. \u0417\u0430 \u0448\u0435\u0441\u0442\u044C \u043C\u0435\u0441\u044F\u0446\u0435\u0432 \u043E\u043D \u0441\u0442\u0430\u043D\u0435\u0442 \u0441\u0430\u043C\u0438\u043C \u0437\u0430\u043F\u0430\u0445\u043E\u043C .</p></div><div class="stanza"><a href="#s14.5" id="s14.5" class="num">14.5</a><p>\u041A\u0430\u043A\u043E\u0439 \u0431\u044B \u0438 \u0433\u0434\u0435 \u043D\u0435 \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u043B\u0441\u044F \u0437\u0430\u043F\u0430\u0445, \u043D\u0430 \u043D\u0435\u043C \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0441\u0440\u0435\u0434\u043E\u0442\u0430\u0447\u0438\u0432\u0430\u0442\u044C\u0441\u044F. \u0417\u0430 \u0442\u0440\u0438 \u0433\u043E\u0434\u0430 \u043E\u043D \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u0441\u0438\u0434\u0434\u0445\u0438 \u0443\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u044F \u043F\u044F\u0442\u044C\u044E \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u0430\u043C\u0438 .</p></div><div class="stanza"><a href="#s14.6" id="s14.6" class="num">14.6</a><p>\u0412\u044B\u0448\u0435 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u0444\u043E\u0440\u043C\u0443 \u0410\u0442\u043C\u0430\u043D\u0430 \u0432 \u0441\u0435\u0440\u0434\u0446\u0435. \u0417\u0430 \u0442\u0440\u0438 \u0433\u043E\u0434\u0430 (\u0439\u043E\u0433\u0438\u043D) \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u0437\u043D\u0430\u043D\u0438\u0435 \u0443\u0440\u043E\u0432\u043D\u044F \u0437\u0430\u043F\u0430\u0445\u0430 .</p></div><div class="stanza"><a href="#s14.7" id="s14.7" class="num">14.7</a><p>\u0421\u043E\u0437\u0435\u0440\u0446\u0430\u044E\u0449\u0438\u0439 \u0441\u043B\u0435\u0433\u043A\u0430 \u0441\u0438\u044F\u044E\u0449\u0438\u0439 (\u043E\u0431\u0440\u0430\u0437 \u0437\u0430\u043F\u0430\u0445\u0430) \u043B\u0438\u0448\u0435\u043D\u043D\u044B\u0439 \u043C\u0430\u043D\u0434\u0430\u043B\u044B, \u0443\u0437\u0440\u0438\u0442 \u0432\u0441\u0435\u0445 \u043E\u0431\u0438\u0442\u0430\u0442\u0435\u043B\u0435\u0439 (\u0432\u0445\u043E\u0434\u044F\u0449\u0438\u0445) \u0432 \u0443\u0440\u043E\u0432\u0435\u043D\u044C \u0437\u0430\u043F\u0430\u0445\u0430 .</p></div><div class="stanza"><a href="#s14.8" id="s14.8" class="num">14.8</a><p>\u0421\u043E\u0437\u0435\u0440\u0446\u0430\u044F \u0442\u0430\u043C \u043D\u0430\u0437\u0432\u0430\u043D\u043D\u044B\u0439 \u043E\u0431\u0440\u0430\u0437 \u0442\u0430\u0442\u0442\u0432\u044B \u0437\u0435\u043C\u043B\u0438, (\u0439\u043E\u0433\u0438\u043D) \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u043E \u0441 \u043D\u0435\u0439, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044F, \u043A\u0430\u043A \u0440\u0430\u043D\u0435\u0435, \u043D\u0430 \u0432\u0442\u043E\u0440\u043E\u043C \u0443\u0440\u043E\u0432\u043D\u0435 .</p></div><div class="stanza"><a href="#s14.9" id="s14.9" class="num">14.9</a><p>\u0421\u043E\u0437\u0435\u0440\u0446\u0430\u044F \u0442\u0430\u043C \u0441\u0432\u043E\u044E \u0444\u043E\u0440\u043C\u0443, \u0441\u0438\u044F\u044E\u0449\u0443\u044E, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0443\u044E \u043D\u0438\u0436\u0435, \u043E\u043D \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u0432\u043B\u0430\u0434\u044B\u0447\u0435\u0441\u0442\u0432\u043E \u043D\u0430\u0434 \u043D\u0435\u0439 \u043E\u043F\u0438\u0441\u0430\u043D\u043D\u044B\u043C \u0432\u044B\u0448\u0435 \u043F\u0443\u0442\u0435\u043C .</p></div><div class="stanza"><a href="#s14.10" id="s14.10" class="num">14.10</a><p>\u0417\u0430\u0442\u0435\u043C \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0432\u0441\u0435 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C (\u043C\u0435\u0442\u043E\u0434\u043E\u043C), \u043F\u043E\u0434\u043E\u0431\u043D\u044B\u043C \u043E\u043F\u0438\u0441\u0430\u043D\u043D\u043E\u043C\u0443 \u0434\u043B\u044F \u0432\u044B\u0448\u0435 \u0442\u0430\u0442\u0442\u0432\u044B \u0437\u0435\u043C\u043B\u0438. \u0417\u0430\u0442\u0435\u043C \u0432\u044B\u0448\u0435 (\u0439\u043E\u0433\u0438\u043D) \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u043F\u043B\u043E\u0434 \u0435\u0435 \u0438\u0437\u043D\u0430\u0447\u0430\u043B\u044C\u043D\u043E\u0439 \u0444\u043E\u0440\u043C\u044B, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0438\u0439 \u043D\u0430 \u0443\u0440\u043E\u0432\u043D\u0435 \u0437\u0430\u043F\u0430\u0445\u0430 .</p></div><div class="stanza"><a href="#s14.11" id="s14.11" class="num">14.11</a><p>\u0422\u0435\u043F\u0435\u0440\u044C \u043F\u043E\u0432\u0435\u0434\u0430\u044E \u043E \u0434\u0445\u0430\u0440\u0430\u043D\u0435 \u043E\u0431\u0440\u0430\u0437\u0430 \u0432\u043A\u0443\u0441\u0430 \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u0435\u043C\u043E\u0435 \u0439\u043E\u0433\u0438\u043D\u0430\u043C\u0438, \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0435\u0439 \u0443 \u0439\u043E\u0433\u0438\u043D\u043E\u0432 \u043E\u0431\u0440\u0435\u0442\u0430\u0435\u0442\u0441\u044F \u0432\u0435\u0437\u0434\u0435\u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C .</p></div><div class="stanza"><a href="#s14.12" id="s14.12" class="num">14.12</a><p>\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u0432\u043E\u0434\u0443, \u044F\u0432\u043B\u044F\u044E\u0449\u0443\u044E\u0441\u044F \u0441 \u043F\u0443\u0437\u044B\u0440\u044F\u043C\u0438 \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0443\u044E \u043D\u0430 \u043A\u043E\u043D\u0447\u0438\u043A\u0435 \u044F\u0437\u044B\u043A\u0430, \u043A\u0430\u043A \u0442\u0430\u043D\u043C\u0430\u0442\u0440\u0443, \u0441\u043E\u0434\u0435\u0440\u0436\u0430\u0449\u0443\u044E\u0441\u044F \u043D\u0430 \u043A\u043E\u043D\u0447\u0438\u043A\u0435 \u044F\u0437\u044B\u043A\u0430 .</p></div><div class="stanza"><a href="#s14.13" id="s14.13" class="num">14.13</a><p>\u041F\u0440\u043E\u0445\u043B\u0430\u0434\u043D\u0430\u044F, \u043E\u0431\u043B\u0430\u0434\u0430\u044E\u0449\u0430\u044F \u0448\u0435\u0441\u0442\u044C\u044E \u0432\u043A\u0443\u0441\u0430\u043C\u0438, \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0435\u043C\u0430\u044F \u0432\u043C\u0435\u0441\u0442\u0435 \u0441 \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0435\u0439 \u0441 \u043D\u0435\u0439 \u0435\u0435 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0439 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C\u044E. \u0417\u0430 \u043C\u0435\u0441\u044F\u0446 \u0443 \u043D\u0435\u0433\u043E \u043F\u043E\u044F\u0432\u044F\u0442\u0441\u044F \u0435\u0435 \u0441\u043B\u0430\u0434\u043A\u0438\u0439 \u0432\u043A\u0443\u0441 .</p></div><div class="stanza"><a href="#s14.14" id="s14.14" class="num">14.14</a><p>\u041A\u043E\u0433\u0434\u0430 \u043E\u043D \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u0441\u043B\u0430\u0434\u043E\u0441\u0442\u044C, \u043E\u0441\u0442\u0430\u0432\u0438\u0432 \u0441\u043E\u043B\u0435\u043D\u043D\u044B\u0439 \u0438 \u043F\u0440\u043E\u0447\u0438\u0435, (\u0432\u043A\u0443\u0441\u044B), \u0442\u043E\u0433\u0434\u0430, \u043D\u0435\u0441\u043E\u043C\u043D\u0435\u043D\u043D\u043E, \u0439\u043E\u0433\u0438\u043D \u0437\u0430 \u0448\u0435\u0441\u0442\u044C \u043C\u0435\u0441\u044F\u0446\u0435\u0432 \u0441\u0442\u0430\u043D\u0435\u0442 \u043F\u043E\u0431\u0435\u0434\u0438\u0442\u0435\u043B\u0435\u043C \u0441\u043C\u0435\u0440\u0442\u0438 .</p></div><div class="stanza"><a href="#s14.15" id="s14.15" class="num">14.15</a><p>\u0421\u0432\u043E\u0431\u043E\u0434\u043D\u044B\u0439 \u043E\u0442 \u0441\u0442\u0430\u0440\u043E\u0441\u0442\u0438 \u0438 \u0431\u043E\u043B\u0435\u0437\u043D\u0435\u0439, \u043D\u0430\u0434\u0435\u043B\u0435\u043D\u043D\u044B\u0439 \u0447\u0435\u0440\u043D\u044B\u043C\u0438 \u0432\u043E\u043B\u043E\u0441\u0430\u043C\u0438, \u043E\u043D \u0431\u0443\u0434\u0435\u0442 \u0436\u0438\u0442\u044C \u043F\u043E\u043A\u0430 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 \u043B\u0443\u043D\u0430, \u0437\u0432\u0435\u0437\u0434\u044B \u0438 \u0441\u043E\u043B\u043D\u0446\u0435 .</p></div><div class="stanza"><a href="#s14.16" id="s14.16" class="num">14.16</a><p>\u0421\u043E\u0437\u0435\u0440\u0446\u0430\u044F \u0435\u0433\u043E \u0432 \u0438\u0437\u043D\u0430\u0447\u0430\u043B\u044C\u043D\u043E\u0439 \u0444\u043E\u0440\u043C\u0435, \u0432 \u043E\u043F\u0438\u0441\u0430\u043D\u043D\u043E\u043C \u043F\u0440\u0435\u0436\u0434\u0435 \u043E\u0431\u0440\u0430\u0437\u0435 \u043F\u0443\u0437\u044B\u0440\u0435\u0439, (\u0439\u043E\u0433\u0438\u043D) \u043E\u0431\u0440\u0435\u0442\u0430\u0435\u0442 \u043F\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u0435 \u0443\u0440\u043E\u0432\u043D\u044F \u0432\u043E\u0434\u044B. \u0427\u0442\u043E \u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C \u0443\u0434\u0438\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u0435\u0439?</p></div><div class="stanza"><a href="#s14.17" id="s14.17" class="num">14.17</a><p>\u042D\u0442\u0430 \u0441\u043E\u0435\u0434\u0438\u043D\u0435\u043D\u043D\u0430\u044F \u0441 \u043C\u043E\u043B\u043D\u0435\u043D\u0438\u0435\u0439 \u0434\u0445\u044C\u044F\u043D\u0430, \u043B\u0438\u0448\u0435\u043D\u043D\u0430\u044F \u043E\u043F\u043E\u0440\u044B \u043F\u0440\u043E\u0438\u0437\u0432\u043E\u0434\u0438\u0442 \u0437\u0430 (\u043D\u0435\u0441\u043A\u043E\u043B\u044C\u043A\u043E) \u043B\u0435\u0442 \u0432\u0441\u0435, \u0447\u0442\u043E \u0441\u043E\u0434\u0435\u0440\u0436\u0438\u0442\u0441\u044F \u043D\u0430 \u0443\u0440\u043E\u0432\u043D\u0435 \u0432\u043E\u0434\u044B .</p></div><div class="stanza"><a href="#s14.18" id="s14.18" class="num">14.18</a><p>\u0421\u043E\u0437\u0435\u0440\u0446\u0430\u044F \u043E\u043F\u0438\u0441\u0430\u043D\u043D\u044B\u0439 \u0432\u044B\u0448\u0435 \u043E\u0431\u0440\u0430\u0437 \u0442\u0430\u0442\u0442\u0432\u044B \u0432\u043E\u0434\u044B, (\u0439\u043E\u0433\u0438\u043D) \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442 \u0432\u0441\u0435\u0433\u043E, \u0440\u043E\u0436\u0434\u0435\u043D\u043D\u043E\u0433\u043E \u043D\u0430 \u0443\u0440\u043E\u0432\u043D\u0435 \u0432\u043A\u0443\u0441\u0430 .</p></div><div class="stanza"><a href="#s14.19" id="s14.19" class="num">14.19</a><p>\u0422\u0435\u043F\u0435\u0440\u044C \u043F\u043E\u0432\u0435\u0434\u0430\u044E \u043E \u0431\u043B\u0430\u0433\u043E\u0439 \u0434\u0445\u0430\u0440\u0430\u043D\u0435, \u043D\u0430\u0434\u0435\u043B\u044F\u044E\u0449\u0435\u0439 \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C \u0432\u0438\u0434\u0435\u043D\u0438\u0435\u043C, \u043D\u0430\u0434\u0435\u043B\u044F\u044E\u0449\u0435\u0439 \u0432\u0441\u0435\u043C\u0438 \u0441\u0438\u0434\u0434\u0445\u0438, \u0441\u043E\u0434\u0435\u0440\u0436\u0430\u0449\u0435\u0439\u0441\u044F \u0432 \u0440\u0443\u043F\u0430 \u0442\u0430\u043D\u043C\u0430\u0442\u0440\u0435 .</p></div><div class="stanza"><a href="#s14.20" id="s14.20" class="num">14.20</a><p>\u0419\u043E\u0433\u0438\u043D\u0443 \u0441\u043B\u0435\u0434\u0443\u0435\u0442, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044F \u0432 \u0443\u0435\u0434\u0438\u043D\u0435\u043D\u043D\u043E\u043C \u043C\u0435\u0441\u0442\u0435, \u043D\u0435\u043C\u0438\u0433\u0430\u044E\u0449\u0438\u043C \u0432\u0437\u0433\u043B\u044F\u0434\u043E\u043C \u0432\u0438\u0434\u0435\u0442\u044C \u0432\u0441\u0435 \u0432 \u0432\u0438\u0434\u0435 \u043E\u0441\u0435\u043D\u043D\u0435\u0433\u043E \u043E\u0431\u043B\u0430\u043A\u0430;</p></div><div class="stanza"><a href="#s14.21" id="s14.21" class="num">14.21</a><p>\u0422\u0430\u043A \u0441\u043E\u0441\u0440\u0435\u0434\u043E\u0442\u0430\u0447\u0438\u0432\u0430\u044F \u0443\u043C, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u0442\u044C \u0442\u0430\u043C \u0434\u0435\u0441\u044F\u0442\u044C \u0434\u043D\u0435\u0439 \u0434\u043E \u0442\u0435\u0445 \u043F\u043E\u0440 \u043F\u043E\u043A\u0430 \u043D\u0435 \u0443\u0432\u0438\u0434\u0438\u0442 \u0447\u0440\u0435\u0437\u0432\u044B\u0447\u0430\u0439\u043D\u043E \u0442\u043E\u043D\u043A\u0443\u044E \u0431\u0438\u043D\u0434\u0443 .</p></div><div class="stanza"><a href="#s14.22" id="s14.22" class="num">14.22</a><p>\u041D\u0435\u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0442\u0430\u043C \u0431\u0435\u043B\u044B\u0435, \u043D\u0435\u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043A\u0440\u0430\u0441\u043D\u044B\u0435, \u0436\u0435\u043B\u0442\u044B\u0435, \u0434\u0440\u0443\u0433\u0438\u0435 \u0441\u0438\u043D\u0438\u0435- \u0443\u0432\u0438\u0434\u0435\u0432 \u0438\u0445, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u0440\u0435\u0434\u0435\u043B\u044C\u043D\u043E \u0441\u043E\u0441\u0440\u0435\u0434\u043E\u0442\u043E\u0447\u0438\u0442\u044C \u0443\u043C, \u043D\u0435 \u043E\u0442\u0432\u043B\u0435\u043A\u0430\u044F \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435 \u043D\u0438 \u043D\u0430 \u0447\u0442\u043E \u0438\u043D\u043E\u0435 .</p></div><div class="stanza"><a href="#s14.23" id="s14.23" class="num">14.23</a><p>\u0427\u0435\u0440\u0435\u0437 \u0448\u0435\u0441\u0442\u044C \u043C\u0435\u0441\u044F\u0446\u0435\u0432 \u043E\u043D \u0443\u0432\u0438\u0434\u0438\u0442 \u0432 \u043D\u0438\u0445 \u0432\u0435\u043B\u0438\u043A\u043E\u0435 \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u043E \u0444\u043E\u0440\u043C, \u0437\u0430 \u0442\u0440\u0438 \u0433\u043E\u0434\u0430 \u043E\u043D\u0438, \u0432\u043C\u0435\u0441\u0442\u0435 \u0441 \u0441\u0438\u044F\u044E\u0449\u0438\u043C \u0441\u0432\u0435\u0442\u043E\u043C, \u0441\u0442\u0430\u043D\u0443\u0442 \u0443\u0441\u0442\u043E\u0439\u0447\u0438\u0432\u044B\u043C\u0438 .</p></div><div class="stanza"><a href="#s14.24" id="s14.24" class="num">14.24</a><p>\u0411\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0442\u0430\u043A\u043E\u0439 \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0435 \u0437\u0430 \u0434\u0432\u0430 \u0433\u043E\u0434\u0430, \u043E\u043D \u0443\u0432\u0438\u0434\u0438\u0442 \u043E\u0431\u0440\u0430\u0437\u044B \u0431\u0438\u043C\u0431\u0430, \u0447\u0435\u0440\u0435\u0437 \u0437\u0430 \u0433\u043E\u0434, \u043E\u043D \u0443\u0432\u0438\u0434\u0438\u0442 \u043E\u0433\u043E\u043D\u044C, \u0437\u0430 \u0448\u0435\u0441\u0442\u044C \u043C\u0435\u0441\u044F\u0446\u0435\u0432 \u2013 \u043E\u0431\u0440\u0430\u0437 \u043F\u0443\u0440\u0443\u0448\u0438 .</p></div><div class="stanza"><a href="#s14.25" id="s14.25" class="num">14.25</a><p>\u0417\u0430 \u0442\u0440\u0438 \u043C\u0435\u0441\u044F\u0446\u0430 \u2013 \u043F\u0440\u043E\u043D\u0438\u043A\u0430\u044E\u0449\u0438\u0439 \u043E\u0433\u043E\u043D\u044C, \u0437\u0430 \u043C\u0435\u0441\u044F\u0446 \u2013 \u0432\u0441\u0435\u043F\u0440\u043E\u043D\u0438\u043A\u0430\u044E\u0449\u0438\u0439. \u0417\u0430 \u043E\u043F\u0438\u0441\u0430\u043D\u043D\u0443\u044E \u0432\u044B\u0448\u0435 \u043F\u043E\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C \u0432\u0440\u0435\u043C\u0435\u043D\u0438, (\u044F\u0432\u0438\u0442\u0441\u044F) \u0443\u0440\u043E\u0432\u0435\u043D\u044C \u0444\u043E\u0440\u043C\u044B;</p></div><div class="stanza"><a href="#s14.26" id="s14.26" class="num">14.26</a><p>(\u0419\u043E\u0433\u0438\u043D) \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u043F\u043B\u043E\u0434 \u0438\u0445 \u0432\u0441\u0435\u0445, \u0443 \u043D\u0435\u0433 \u043E \u043F\u043E\u044F\u0432\u0438\u0442\u0441\u044F \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 \u0437\u0440\u0435\u043D\u0438\u0435. \u0422\u0430\u043A\u043E\u0432\u0430 \u043B\u0438\u0448\u0435\u043D\u043D\u0430\u044F \u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u0438\u0439 \u0434\u0445\u0430\u0440\u0430\u043D\u0430, \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u044E\u0449\u0430\u044F\u0441\u044F \u043E\u0442 \u0435\u0435 \u0432\u044B\u043F\u043E\u043B\u043D\u0435\u043D\u0438\u044F .</p></div><div class="stanza"><a href="#s14.27" id="s14.27" class="num">14.27</a><p>\u0412 \u0441\u0432\u043E\u0438\u0445 \u043F\u044F\u0442\u043D\u0430\u0434\u0446\u0430\u0442\u044C \u043E\u0442\u0434\u0435\u043B\u044C\u043D\u044B\u0445 \u0432\u0438\u0434\u0430\u0445, \u043E\u043D\u0430 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0441\u0430\u043C\u0430. \u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u043E\u043D\u0430- \u0441\u0430\u043C\u043E\u0434\u043E\u0441\u0442\u0430\u0442\u043E\u0447\u043D\u0430, \u0441\u043B\u0435\u0434\u0443\u0435\u0442, \u043D\u0435 \u0441\u043E\u043C\u043D\u0435\u0432\u0430\u044F\u0441\u044C, \u0435\u0435 \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u043E\u0432\u0430\u0442\u044C. \u041A \u0447\u0435\u043C\u0443 \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u043E \u043F\u0440\u043E\u0447\u0438\u0445 \u043F\u0438\u0441\u0430\u043D\u0438\u0439?</p></div><div class="stanza"><a href="#s14.28" id="s14.28" class="num">14.28</a><p>\u0422\u0435\u043F\u0435\u0440\u044C \u043F\u043E\u0432\u0435\u0434\u0430\u044E \u0422\u0435\u0431\u0435 \u0434\u0440\u0443\u0433\u0443\u044E \u0434\u0445\u0430\u0440\u0430\u043D\u0443, \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0443\u044E \u0438\u0437 \u043E\u0441\u044F\u0437\u0430\u043D\u0438\u044F, \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u043A\u043E\u0442\u043E\u0440\u043E\u0439 \u0439\u043E\u0433\u0438\u043D \u043E\u0431\u0440\u0435\u0442\u0430\u0435\u0442 \u0432\u0430\u0434\u0436\u0440\u043D\u043E\u0435 \u0442\u0435\u043B\u043E .</p></div><div class="stanza"><a href="#s14.29" id="s14.29" class="num">14.29</a><p>\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u0441\u0435\u0431\u044F (\u0410\u0442\u043C\u0430\u043D) \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0438\u043C \u0432\u043D\u0443\u0442\u0440\u0438 \u0448\u0435\u0441\u0442\u0438\u0443\u0433\u043E\u043B\u044C\u043D\u043E\u0439 \u043C\u0430\u043D\u0434\u0430\u043B\u044B, \u043A\u0430\u0436\u0434\u0430\u044F \u0447\u0430\u0441\u0442\u044C \u043A\u043E\u0442\u043E\u0440\u043E\u0439, \u043F\u043E\u0434\u043E\u0431\u043D\u043E \u0446\u0432\u0435\u0442\u043A\u0443 \u043A\u0443\u043A\u0448\u043C\u0430 \u0430\u043D\u0434\u0436\u043D\u0430\u043D\u0430, \u043D\u0430\u043F\u043E\u043B\u043D\u0435\u043D\u0430 \u0441\u0432\u0435\u0442\u043E\u043C .</p></div><div class="stanza"><a href="#s14.30" id="s14.30" class="num">14.30</a><p>\u0417\u0430\u0442\u0435\u043C, \u0432\u0441\u0435\u0433\u043E \u0437\u0430 \u0434\u0435\u0441\u044F\u0442\u044C \u0434\u043D\u0435\u0439, \u043E \u0414\u0435\u0432\u0438, \u043E\u043D \u0441\u0442\u0430\u043D\u0435\u0442 (\u0435\u0434\u0438\u043D\u044B\u043C) \u0441 \u043F\u0440\u0438\u043A\u043E\u0441\u043D\u043E\u0432\u0435\u043D\u0438\u0435\u043C \u043C\u0443\u0440\u0430\u0432\u044C\u044F, \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u044F \u0435\u0433\u043E .</p></div><div class="stanza"><a href="#s14.31" id="s14.31" class="num">14.31</a><p>\u041E\u043D \u0431\u0443\u0434\u0435\u0442 \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u0442\u044C \u0432 \u0432\u0430\u0434\u0436\u0440\u043D\u043E\u043C \u0442\u0435\u043B\u0435, \u043E\u043D \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u0435\u0433\u043E, \u043A\u0430\u043A \u0431\u044B\u043B\u043E \u0441\u043A\u0430\u0437\u0430\u043D\u043E \u0440\u0430\u043D\u0435\u0435, \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u044F \u0435\u0433\u043E \u0432 \u043F\u0435\u0440\u0432\u0438\u0447\u043D\u043E\u0439 \u0444\u043E\u0440\u043C\u0435, \u0432 \u043E\u0431\u0440\u0430\u0437\u0435 \u043C\u0430\u043D\u0434\u0430\u043B\u044B .</p></div><div class="stanza"><a href="#s14.32" id="s14.32" class="num">14.32</a><p>\u041E\u0431\u0440\u0435\u0442\u044F \u0437\u043D\u0430\u043D\u0438\u044F \u0434\u0435\u044F\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438 <em>\u0441\u043F\u0430\u0440\u0448\u0430 \u0442\u0430\u0442\u0442\u0432\u044B</em>, \u043A\u0435\u043C \u043E\u043D \u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C \u043F\u043E\u0431\u0435\u0436\u0434\u0435\u043D? \u0414\u043B\u044F \u043E\u0431\u0440\u0435\u0442\u0435\u043D\u0438\u044F \u0433\u043E\u0441\u043F\u043E\u0434\u0441\u0442\u0432\u0430 \u043D\u0430\u0434 \u043D\u0435\u0439 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u0441\u0435\u0431\u044F \u0432 \u043C\u0430\u043D\u0434\u0430\u043B\u0435 .</p></div><div class="stanza"><a href="#s14.33" id="s14.33" class="num">14.33</a><p>\u0411\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0435\u0435 \u0440\u0435\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u0438, \u043E\u043D \u0441\u0442\u0430\u043D\u0435\u0442 \u0437\u043D\u0430\u044E\u0449\u0438\u043C \u0432\u0441\u0435 \u043F\u0440\u0438\u043A\u043E\u0441\u043D\u043E\u0432\u0435\u043D\u0438\u044F. \u0417\u0430\u043A\u0440\u044B\u0432 \u0443\u0448\u0438, \u043F\u0443\u0441\u0442\u044C \u043E\u043D \u0441\u0442\u0430\u0440\u0430\u0442\u0435\u043B\u044C\u043D\u043E \u0432\u0441\u043B\u0443\u0448\u0438\u0432\u0430\u0435\u0442\u0441\u044F \u043F\u0440\u0438 \u0437\u0430\u043A\u0440\u044B\u0442\u044B\u0445 \u0433\u043B\u0430\u0437\u0430\u0445 .</p></div><div class="stanza"><a href="#s14.34" id="s14.34" class="num">14.34</a><p>\u0415\u0441\u043B\u0438 \u043E\u043D \u0443\u0441\u043B\u044B\u0448\u0438\u0442 \u0432\u0435\u043B\u0438\u043A\u0438\u0439 \u0433\u0440\u043E\u043C, \u043D\u0430 \u043D\u0435\u043C \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0441\u0440\u0435\u0434\u043E\u0442\u043E\u0447\u0438\u0442\u044C\u0441\u044F. \u0417\u0430 \u0434\u0435\u0441\u044F\u0442\u044C \u0434\u043D\u0435\u0439 \u0443 \u043D\u0435\u0433\u043E \u044F\u0432\u0438\u0442\u0441\u044F (\u0437\u043D\u0430\u043D\u0438\u0435) \u0443\u0442\u0440\u043E\u0431\u043D\u043E\u0433\u043E \u043E\u0433\u043D\u044F .</p></div><div class="stanza"><a href="#s14.35" id="s14.35" class="num">14.35</a><p>\u0417\u0430 \u0448\u0435\u0441\u0442\u044C \u043C\u0435\u0441\u044F\u0446\u0435\u0432 \u0443 \u043D\u0435\u0433\u043E \u043F\u043E\u044F\u0432\u0438\u0442\u0441\u044F \u0437\u043D\u0430\u043D\u0438\u0435 \u0441\u043B\u044B\u0448\u0438\u043C\u043E\u0433\u043E \u0438\u0437\u0434\u0430\u043B\u0435\u043A\u0430. \u041F\u043E\u043A\u0430 \u043E\u043D\u043E \u043D\u0435 \u043D\u0430\u0441\u0442\u0443\u043F\u0438\u043B\u043E \u043E\u043A\u043E\u043D\u0447\u0430\u0442\u0435\u043B\u044C\u043D\u043E, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u043C\u0435\u0434\u043B\u0435\u043D\u043D\u043E \u0438 \u043F\u043E\u0441\u0442\u0435\u043F\u0435\u043D\u043D\u043E (\u0432\u0441\u043B\u0443\u0448\u0438\u0432\u0430\u044F\u0441\u044C) .</p></div><div class="stanza"><a href="#s14.36" id="s14.36" class="num">14.36</a><p>\u0411\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u044D\u0442\u043E\u0439 \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0435, \u043D\u0435 \u043E\u0442\u0432\u043B\u0435\u043A\u0430\u044F\u0441\u044C \u0443\u043C\u043E\u043C \u043D\u0438 \u043D\u0430 \u0447\u0442\u043E \u0438\u043D\u043E\u0435, \u043F\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442\u0441\u044F \u0421\u0443\u0449\u043D\u043E\u0441\u0442\u044C <em>\u0441\u0430\u043A\u0430\u043B\u044B.</em> (\u0411\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0435\u0439, \u0439\u043E\u0433\u0438\u043D) \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u0437\u043D\u0430\u043D\u0438\u0435 \u0443\u0440\u043E\u0432\u043D\u044F \u0437\u0432\u0443\u043A\u0430, \u0438 \u0431\u0443\u0434\u0435\u0442 \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u0442\u044C \u0432 \u043D\u0435\u043C \u0443\u0441\u0442\u043E\u0439\u0447\u0438\u0432\u043E .</p></div><div class="stanza"><a href="#s14.37" id="s14.37" class="num">14.37</a><p>\u041A\u0430\u043A\u043E\u0439 \u0431\u044B \u0437\u0432\u0443\u043A \u043E\u043D \u043D\u0435 \u0443\u0441\u043B\u044B\u0448\u0430\u043B \u0432\u043D\u0430\u0447\u0430\u043B\u0435, \u0432 \u043A\u043E\u043D\u0446\u0435 \u043D\u0435\u0433\u043E- \u0437\u0432\u0443\u043A, \u043F\u043E\u0434\u043E\u0431\u043D\u044B\u0439 \u0440\u0430\u043A\u043E\u0432\u0438\u043D\u0435, \u0435\u0441\u0442\u044C \u0444\u043E\u0440\u043C\u0430 \u043F\u0440\u0430\u043B\u0430\u044F \u043A\u0430\u043B\u0430, \u0435\u0433\u043E \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u043E\u0432\u0430\u0442\u044C \u0436\u0435\u043B\u0430\u044E\u0449\u0438\u043C \u0435\u0433\u043E \u043F\u043B\u043E\u0434\u0430 .</p></div><div class="stanza"><a href="#s14.38" id="s14.38" class="num">14.38</a><p>\u041A\u043E\u0433\u0434\u0430 \u043E\u043D \u043F\u0440\u0435\u0432\u0437\u043E\u0439\u0434\u0435\u0442 \u0435\u0435, (\u0438 \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0435\u0442) \u043E\u0431\u043E\u043B\u043E\u0447\u043A\u0438 \u0434\u0440\u0443\u0433\u043E\u0433\u043E \u0437\u0432\u0443\u043A\u0430, \u043E\u043D \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u0432\u0438\u0434\u0436\u043D\u0430\u043D\u0430\u043A\u0430\u043B\u0430, \u0432 \u043D\u0435\u043C \u043E\u043D \u0431\u0443\u0434\u0435\u0442 \u043D\u0435\u043F\u043E\u0431\u0435\u0434\u0438\u043C .</p></div><div class="stanza"><a href="#s14.39" id="s14.39" class="num">14.39</a><p>(\u0417\u0432\u0443\u043A) \u0434\u043E\u0441\u0442\u0430\u0432\u043B\u044F\u044E\u0449\u0438\u0439 \u0440\u0430\u0434\u043E\u0441\u0442\u044C \u0443\u043C\u0443, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0435\u0442\u0441\u044F \u0432\u0441\u043B\u0435\u0434 \u0437\u0430 \u043D\u0438\u043C, \u0438\u0437\u0432\u0435\u0441\u0442\u0435\u043D \u0439\u043E\u0433\u0438\u043D\u0430, \u0436\u0435\u043B\u0430\u044E\u0449\u0438\u043C \u0439\u043E\u0433\u0438, \u043A\u0430\u043A \u043C\u0430\u043D\u0442\u0440\u0430 .</p></div><div class="stanza"><a href="#s14.40" id="s14.40" class="num">14.40</a><p>\u0417\u0430\u0442\u0435\u043C \u0441\u043B\u044B\u0448\u0438\u0442\u0441\u044F \u0434\u0440\u0443\u0433\u043E\u0439 \u0437\u0432\u0443\u043A, \u043F\u043E\u0434\u043E\u0431\u043D\u044B\u0439 \u0441\u043F\u043E\u043A\u043E\u0439\u043D\u043E\u043C\u0443 \u0433\u0443\u0434\u0435\u043D\u0438\u044E \u0440\u0430\u043A\u043E\u0432\u0438\u043D\u044B. \u042D\u0442\u043E \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F (\u0443\u0440\u043E\u0432\u0435\u043D\u0435\u043C) \u043C\u0430\u043D\u0442\u0440\u0435\u0448\u0438, \u0434\u0430\u044E\u0449\u0435\u0439 \u043F\u043B\u043E\u0434 \u0432\u0441\u0435\u0445 \u0441\u0438\u0434\u0434\u0445\u0438 .</p></div><div class="stanza"><a href="#s14.41" id="s14.41" class="num">14.41</a><p>\u0417\u0432\u0443\u043A \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u043F\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043F\u043E\u0441\u043B\u0435 \u043F\u0440\u0435\u043A\u0440\u0430\u0449\u0435\u043D\u0438\u044F \u0433\u0443\u0434\u0435\u043D\u0438\u044F \u0440\u0430\u043A\u043E\u0432\u0438\u043D\u044B, \u0435\u0441\u0442\u044C \u0443\u0440\u043E\u0432\u0435\u043D\u044C \u043C\u0430\u043D\u0442\u0440\u0435\u0448\u0438, \u0432\u0435\u043B\u0438\u043A\u0430\u044F \u043F\u0440\u0438\u0447\u0438\u043D\u0430 \u0441\u0438\u0434\u0434\u0445\u0438 .</p></div><div class="stanza"><a href="#s14.42" id="s14.42" class="num">14.42</a><p>\u0411\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u043D\u0435\u043F\u0440\u0435\u043A\u0440\u0430\u0449\u0430\u044E\u0449\u0435\u043C\u0443 \u0433\u0443\u0434\u0435\u043D\u0438\u044E \u043D\u0430\u0434\u044B \u0432 \u043D\u0435\u0431\u0435, \u043F\u043E\u0434\u043E\u0431\u043D\u043E\u0439 \u0432\u0438\u043D\u0435, \u043E\u043D \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0435\u0442 \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u044F. \u0417\u0432\u0443\u043A \u043F\u043E\u0434\u043E\u0431\u043D\u044B\u0439 \u0435\u0439 \u0438\u0437\u0432\u0435\u0441\u0442\u0435\u043D \u043A\u0430\u043A \u043E\u0431\u0438\u0442\u0435\u043B\u044C \u0428\u0430\u043C\u0431\u0445\u0443 .</p></div><div class="stanza"><a href="#s14.43" id="s14.43" class="num">14.43</a><p>\u041F\u043E \u043E\u0442\u0434\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438 \u0438 \u043F\u043E \u043F\u043E\u0440\u044F\u0434\u043A\u0443, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u043E\u0432\u0430\u0442\u044C \u0438\u0445 \u0432\u0441\u0435\u0445, \u0442\u043E\u0433\u0434\u0430 \u0432\u0441\u0435\u0437\u043D\u0430\u044E\u0449\u0438\u0439 \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0435\u0442 \u0432\u0441\u0435\u0445 \u0441\u0438\u0434\u0434\u0445\u0438, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044F \u0432 \u043E\u043A\u0440\u0443\u0436\u0435\u043D\u0438\u0438 \u0437\u0432\u0443\u043A\u0430. \u0418\u0442\u0430\u043A, \u0422\u0435\u0431\u0435 \u043D\u0430\u0437\u0432\u0430\u043D\u044B \u0434\u0445\u0430\u0440\u043D\u044B \u043F\u044F\u0442\u0438 \u0442\u0430\u043D\u043C\u0430\u0442\u0440 .</p></div><p>\u0422\u0430\u043A\u043E\u0432\u0430 \u0432 \u0441\u0432\u044F\u0449\u0435\u043D\u043D\u043E\u0439 \xAB\u041C\u0430\u043B\u0438\u043D\u0438 \u0432\u0438\u0434\u0436\u0430\u0439\u043E\u0442\u0442\u0430\u0440\u0430 \u0442\u0430\u043D\u0442\u0440\u0435\xBB \u0447\u0435\u0442\u044B\u0440\u043D\u0430\u0434\u0446\u0430\u0442\u0430\u044F \u0433\u043B\u0430\u0432\u0430</p>',44),l=[c];function p(v,t,e,r,m,f){return i(),a("div",null,l)}var z=s(n,[["render",p]]);export{h as __pageData,z as default};
